-- =============================================================
-- MIG-038 Phase 5 — V8.4 SLC-842 Default-Seed customer-dse
-- =============================================================
--
-- Phase 5: Default-Markdown aus cockpit/src/content/legal/customer-dse-default.md
-- als customer-dse-Row in legal_documents fuer ALLE bestehenden Teams.
--
-- Idempotent: ON CONFLICT (tenant_team_id, kind) DO NOTHING.
-- Tenant-Admin kann Inhalt via Editor (SLC-844) ueberschreiben.
--
-- Apply-Procedure: .claude/rules/sql-migration-hetzner.md
--   ssh root@91.98.20.191
--   docker ps --format "{{.Names}}" | grep supabase-db
--   echo '<base64>' | base64 -d > /tmp/038_v84_customer_dse_phase5.sql
--   docker exec -i <container> psql -U postgres -d postgres < /tmp/038_v84_customer_dse_phase5.sql
--
-- Markdown-Content ist als base64-String embedded (Risk R1 aus Slice-Spec:
-- $$...$$-Quoting bricht mit eingebetteten $-Zeichen).

INSERT INTO legal_documents (tenant_team_id, kind, content_md)
SELECT
  t.id,
  'customer-dse',
  convert_from(
    decode(
      '',
      'base64'
    ),
    'UTF8'
  )
FROM teams t
ON CONFLICT (tenant_team_id, kind) DO NOTHING;

NOTIFY pgrst, 'reload schema';
